package com.example.app.waitlist; import org.springframework.data.jpa.repository.*; import org.springframework.data.repository.query.Param; import java.time.*; import java.util.*; public interface WaitlistRequestRepository extends JpaRepository<WaitlistRequest,Long>{ List<WaitlistRequest> findByCompanyIdAndStatusInOrderByJoinedAtAsc(Long companyId,Collection<String> statuses); Optional<WaitlistRequest> findByIdAndCompanyId(Long id,Long companyId); @Query("select w from WaitlistRequest w where w.company.id=:companyId and w.status='ACTIVE' and w.dateFrom<=:date and w.dateTo>=:date and (w.service.id=:serviceId or w.service is null) order by w.joinedAt asc") List<WaitlistRequest> findMatches(@Param("companyId")Long companyId,@Param("serviceId")Long serviceId,@Param("date")LocalDate date); }